import { useState, useEffect } from 'react';
import { Moon, Sun, Menu, X, Download } from 'lucide-react';
import { useApp } from '../context/AppContext';
import t from '../i18n/translations';

export default function Navbar() {
  const { dark, setDark, lang, setLang } = useApp();
  const tr = t[lang];
  const [scrolled, setScrolled] = useState(false);
  const [active,   setActive]   = useState('');
  const [open,     setOpen]     = useState(false);

  const links = [
    { id:'about',      label: tr.about },
    { id:'projects',   label: tr.projectsNav },
    { id:'experience', label: tr.experience },
    { id:'certs',      label: tr.certs },
    { id:'contact',    label: tr.contact },
  ];

  useEffect(() => {
    const fn = () => {
      setScrolled(window.scrollY > 40);
      let cur = '';
      document.querySelectorAll('section[id]').forEach(s => {
        if (window.scrollY >= s.offsetTop - 130) cur = s.id;
      });
      setActive(cur);
    };
    window.addEventListener('scroll', fn, { passive: true });
    return () => window.removeEventListener('scroll', fn);
  }, []);

  const navStyle = scrolled ? {
    background: dark ? 'rgba(15,15,20,0.80)' : 'rgba(253,252,249,0.75)',
    backdropFilter: 'blur(28px) saturate(180%)',
    WebkitBackdropFilter: 'blur(28px) saturate(180%)',
    borderBottom: `1px solid ${dark ? 'rgba(255,255,255,0.07)' : 'rgba(255,255,255,0.8)'}`,
    boxShadow: dark ? '0 4px 24px rgba(0,0,0,0.3)' : '0 4px 24px rgba(26,26,46,0.06)',
  } : {};

  const lc = id => active === id ? 'text-amber' : dark ? 'text-white/60 hover:text-white' : 'text-muted2 hover:text-ink';

  return (
    <nav className="fixed inset-x-0 top-0 z-50 flex items-center justify-between px-[5%] py-4 transition-all duration-300" style={navStyle}>
      <a href="#hero" className="font-serif-display text-2xl tracking-tight">
        <span style={{ color: dark ? '#fff' : '#1a1a2e' }}>Ke</span>
        <span className="text-amber">Mo</span>
        <span style={{ color: dark ? '#fff' : '#1a1a2e' }}>O</span>
        <span className="text-amber">.</span>
      </a>

      <ul className="hidden md:flex gap-7">
        {links.map(l => (
          <li key={l.id}>
            <a href={`#${l.id}`} className={`text-sm font-medium transition-colors duration-200 ${lc(l.id)}`}>{l.label}</a>
          </li>
        ))}
      </ul>

      <div className="flex items-center gap-2">
        {/* Download CV */}
        <a href="/assets/kareem-cv.pdf" download="Kareem_Basem_CV.pdf"
          className="hidden md:inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-semibold transition-all"
          style={{
            background: dark ? 'rgba(240,165,0,0.12)' : 'rgba(240,165,0,0.10)',
            border: '1px solid rgba(240,165,0,0.3)',
            color: '#f0a500',
          }}
          title="Download CV">
          <Download size={12} /> CV
        </a>

        {/* Lang */}
        <button onClick={() => setLang(lang === 'en' ? 'ar' : 'en')}
          className={`px-3 py-1.5 rounded-full text-xs font-semibold border transition-all ${dark ? 'border-white/15 text-white/60 hover:border-amber hover:text-amber' : 'border-ink/15 text-muted2 hover:border-amber hover:text-amber'}`}>
          {lang === 'en' ? 'ع' : 'EN'}
        </button>

        {/* Dark */}
        <button onClick={() => setDark(!dark)}
          className={`w-9 h-9 rounded-full border flex items-center justify-center transition-all ${dark ? 'border-white/15 text-amber bg-white/5' : 'border-ink/15 text-muted2 hover:border-amber hover:text-amber'}`}>
          {dark ? <Sun size={15}/> : <Moon size={15}/>}
        </button>

        {/* Hire Me */}
        <a href="mailto:karemalwy1@gmail.com"
          className="hidden md:inline-block px-4 py-2 text-sm font-semibold rounded-full transition-all"
          style={{
            background: dark ? 'rgba(255,255,255,0.08)' : '#1a1a2e',
            color: dark ? '#f0f0f8' : '#fdfcf9',
            border: dark ? '1px solid rgba(255,255,255,0.12)' : 'none',
          }}
          onMouseEnter={e => { e.target.style.background = '#f0a500'; e.target.style.color = '#fff'; }}
          onMouseLeave={e => { e.target.style.background = dark ? 'rgba(255,255,255,0.08)' : '#1a1a2e'; e.target.style.color = dark ? '#f0f0f8' : '#fdfcf9'; }}>
          {tr.hireMe}
        </a>

        <button className="md:hidden" onClick={() => setOpen(!open)}>
          {open ? <X size={22} style={{ color: dark ? '#fff' : '#1a1a2e' }}/> : <Menu size={22} style={{ color: dark ? '#fff' : '#1a1a2e' }}/>}
        </button>
      </div>

      {open && (
        <div className="absolute top-full left-0 right-0 py-4 flex flex-col items-center gap-4 md:hidden"
          style={{ background: dark ? 'rgba(15,15,20,0.95)' : 'rgba(253,252,249,0.95)', backdropFilter: 'blur(20px)', borderBottom: `1px solid ${dark ? 'rgba(255,255,255,0.08)' : 'rgba(26,26,46,0.08)'}` }}>
          {links.map(l => (
            <a key={l.id} href={`#${l.id}`} onClick={() => setOpen(false)} className={`text-sm font-medium ${lc(l.id)}`}>{l.label}</a>
          ))}
          <a href="/assets/kareem-cv.pdf" download="Kareem_Basem_CV.pdf" className="text-amber text-sm font-semibold flex items-center gap-1.5"><Download size={13}/> Download CV</a>
        </div>
      )}
    </nav>
  );
}
